app.service("SongsService",function($http,$q){this.getVisibleSongLists=function(){return $q.all({lists:$http.post("/ajax",{command:"get_all_song_lists"}),settings:$http.post("/ajax",{command:"get_user_settings"})}).then(function(results){var allLists=results.lists.data||[];var settings=results.settings.data;if(settings&&settings.available_lists){var selectedIds=settings.available_lists.split(",");return allLists.filter(function(list){return selectedIds.indexOf(String(list.LIST_ID))!==-1})}return allLists})};this.getLanguages=function(){return $http.post("/ajax",{command:"get_languages"}).then(function(r){return r.data||[]})}});